检索查询 检索查询 对于常用的检索查询，嵌入式SQL提供了常规命令SELECT和FETCH的特殊变体。这些命令使用特殊的INTO子句，用以指定检索出来的数值存储在哪些宿主变量里。SELECT用于返回单行的查询，FETCH用于使用游标返回多行的查询。 使用SELECT /*  
 * 假定有这个表：  
 * CREATE TABLE test1 (a int, b varchar(50)); 
 */
EXEC SQL BEGIN DECLARE SECTION;
    int v1;
    VARCHAR v2;
EXEC SQL END DECLARE SECTION;

    ...

    EXEC SQL SELECT a, b INTO :v1, :v2 FROM test; INTO子句出现在选择列表和FROM子句之间。选择列表和INTO后面的列表的元素（也叫目标列表）个数必须相同。 使用FETCH EXEC SQL BEGIN DECLARE SECTION;
    int v1;
    VARCHAR v2;
EXEC SQL END DECLARE SECTION;
    ...

    EXEC SQL DECLARE foo CURSOR FOR SELECT a, b FROM test;
    ...
    do
    {
        ...
        EXEC SQL FETCH NEXT FROM foo INTO :v1, :v2;
        ...
    } while (...); 这里的INTO子句出现在所有SQL子句后面。

使用非初级类型的宿主变量 使用非初级类型的宿主变量 非初级类型的宿主变量包括数组，typedef，结构体和指针类型的宿主变量。 数组： 有两种将数组作为宿主变量的情况。第一种情况是在char[]或者VARCHAR[]中存储一些文本字符串。第二种情况是可在检索多行查询结果时不使用游标。如果不使用数组，则处理多行查询结果时必须使用游标以及FETCH命令。但是如果使用数组类型作为宿主变量，则一次可以检索多行。数组长度需能容纳查询结果的所有行，否则可能会发生缓冲区溢出。 下面示例为扫描pg_database系统表并且显示所有可用数据库的OID和名称： #include <stdlib.h>
#include <stdio.h>
#include <string.h>

int main(void) 
{
EXEC SQL BEGIN DECLARE SECTION;
    int dbid[8];
    char dbname[8][16];
    int i;
EXEC SQL END DECLARE SECTION;

    memset(dbname, 0, sizeof(char)* 16 * 8);
    memset(dbid, 0, sizeof(int) * 8);
  /* 连接到testdb，需提前创建上testdb库 */
    EXEC SQL CONNECT TO testdb; 
    /* 一次检索多行到数组中。 */ 
    EXEC SQL SELECT oid,datname INTO :dbid, :dbname FROM pg_database; 
    for (i = 0; i < 8; i++) 
        printf("oid=%d, dbname=%s\n", dbid[i], dbname[i]); 
    EXEC SQL COMMIT; 
    EXEC SQL DISCONNECT ALL; 
    return 0; 
} 示例输出（具体值取决于本地环境）： oid=1, dbname=template1 
oid=11510, dbname=template0 
oid=11511, dbname=postgres 
oid=313780, dbname=testdb 
oid=0, dbname= 
oid=0, dbname= 
oid=0, dbname= 结构体 结构体成员变量可用来匹配查询结果列的名称，该结构能在一个宿主变量中处理多列值。 以下示例从pg_database系统表以及使用pg_database_size()函数检索可用数据库的OID、名称和尺寸。在此示例中，按照结构体的成员名匹配SELECT结果的每一列，从而不必把多个宿主变量放在FETCH语句中。 EXEC SQL BEGIN DECLARE SECTION;
    typedef struct
    {
        int oid;
        char datname[65];
        long long int size;
    } dbinfo_t;

    dbinfo_t dbval;
EXEC SQL END DECLARE SECTION;
    memset(&dbval, 0, sizeof(dbinfo_t));

    EXEC SQL DECLARE cur1 CURSOR FOR SELECT oid, datname, pg_database_size(oid) AS size FROM pg_database;     
    EXEC SQL OPEN cur1;

    /* 在达到结果集末尾时，跳出 while 循环 */     
    EXEC SQL WHENEVER NOT FOUND DO BREAK;

    while (1)
    {         
        /* 将多列取到一个结构体中。 */        
        EXEC SQL FETCH FROM cur1 INTO :dbval;          
        /* 打印该结构体的成员。 */         
        printf("oid=%d, datname=%s, size=%lld\n", dbval.oid, dbval.datname, dbval.size);     
    }
    EXEC SQL CLOSE cur1; 示例输出（具体值取决于本地环境）： oid=1, datname=template1, size=4324580 
oid=11510, datname=template0, size=4243460 
oid=11511, datname=postgres, size=4324580 
oid=313780, datname=testdb, size=8183012 结构体宿主变量可将查询结果的部分列转化成结构体字段，其他的查询结果列可以被分配给其它宿主变量。上述的示例也可以使用结构体外部的size宿主变量重新构造： EXEC SQL BEGIN DECLARE SECTION;     
    typedef struct     
    {        
        int oid;        
        char datname[65];     
    } dbinfo_t;   

    dbinfo_t dbval;     
    long long int size; 
EXEC SQL END DECLARE SECTION;      

    memset(&dbval, 0, sizeof(dbinfo_t));      

    EXEC SQL DECLARE cur1 CURSOR FOR SELECT oid, datname, pg_database_size(oid) AS size FROM pg_database;     
    EXEC SQL OPEN cur1;      

    /* 在达到结果集末尾时，跳出 while 循环 */    
    EXEC SQL WHENEVER NOT FOUND DO BREAK;      
    while (1)     
    {         
        /* 将多列取到一个结构中。 */         
        EXEC SQL FETCH FROM cur1 INTO :dbval, :size;          
        /* 打印该结构的成员。 */         
        printf("oid=%d, datname=%s, size=%lld\n", dbval.oid, dbval.datname, size);     
    }  

    EXEC SQL CLOSE cur1; typedef 使用typedef关键字将新类型映射到已有类型： EXEC SQL BEGIN DECLARE SECTION;
typedef char mychartype[40];
typedef long serial_t;
EXEC SQL END DECLARE SECTION; 也可以使用如下命令： EXEC SQL TYPE serial_t IS long; 这种声明不需要写在一个声明段中。 指针 可以声明常见类型的指针： EXEC SQL BEGIN DECLARE SECTION;
int   *intp;
char **charp;
EXEC SQL END DECLARE SECTION;

处理字符串 处理字符串 处理SQL字符串数据类型（例如：varchar、text），有两种方式来声明宿主变量： 方式一：使用char[]（一个char字符串），C语言程序中处理字符数据最常见的方式。 EXEC SQL BEGIN DECLARE SECTION;
    char str[50];
EXEC SQL END DECLARE SECTION; 注意字符串必须控制长度，如果上述示例的宿主变量用作存放查询结果且查询命令返回的字符串长度超过49字节，那么将会发生缓冲区溢出。 方式二：使用VARCHAR类型，ecpg提供的一种特殊类型。在一个VARCHAR类型数组上的定义会被转变成一个struct类型。如下声明： VARCHAR var[180]; 会被转变成： struct varchar_var 
{ 
    int len; 
    char arr[180]; 
} var; 要在一个VARCHAR宿主变量中存储一个字符串，该宿主变量必须被声明为包含零字节为终止符长度的字符串。字段arr存放以零字节为终止符的字符串，字段len保存存储在arr中的字符串的长度，计算长度时不包括终止符。当宿主变量被用于一个查询的输入时，如果strlen(arr)和len结果不同，将使用较短的那一个。 VARCHAR可以被写成大写或小写形式，但是不能大小写混合。 char和VARCHAR类型宿主变量也可以保存其他SQL类型的值，它们将被存储为字符串形式。

处理非初级SQL数据类型 处理非初级SQL数据类型 本节介绍如何处理ecpg应用中非标量以及用户定义的SQL级别的数据类型。注意此处和 使用非初级类型的宿主变量 章节中介绍的对于非初级类型的宿主变量的处理不同。 数组 ecpg不直接支持多维SQL级别数组。一维SQL数组可以被映射到C语言数组类型的宿主变量，反之亦然。但是在创建语句时，如果ecpg并不知道列的类型，则将无法检查C语言数组是否是SQL数组的输入。因此在处理SQL语句的输出时，ecpg需要检查两者是否都是数组。 如果查询语句仅仅访问一个数组的元素，那么用一个能被映射到该元素类型的宿主变量即可。例如：假设列的类型是integer数组，可以使用int类型的宿主变量。如果元素类型是varchar或text，可以使用char[]或VARCHAR[]类型的宿主变量。 示例如下： CREATE TABLE t3 ( 
    ii integer[] 
);  
testdb=> SELECT * FROM t3; 
     ii 
------------- 
 {1,2,3,4,5} 
(1 row) 如下示例检索数组的第四个元素并且把它存储到一个int类型的宿主变量中： EXEC SQL BEGIN DECLARE SECTION; 
    int ii; 
EXEC SQL END DECLARE SECTION;  

    EXEC SQL DECLARE cur1 CURSOR FOR SELECT ii[4] FROM t3; 
    EXEC SQL OPEN cur1;  

    EXEC SQL WHENEVER NOT FOUND DO BREAK;  

    while (1) 
    { 
        EXEC SQL FETCH FROM cur1 INTO :ii ; 
        printf("ii=%d\n", ii); 
    }  
    EXEC SQL CLOSE cur1; 示例输出： ii=4 若要把多个数组元素映射到一个数组类型宿主变量中，数组列的每一个元素以及宿主变量数组的每一个元素都需单独处理。例如： EXEC SQL BEGIN DECLARE SECTION; 
    int ii_a[8]; 
EXEC SQL END DECLARE SECTION;  

    EXEC SQL DECLARE cur1 CURSOR FOR SELECT ii[1], ii[2], ii[3], ii[4] FROM t3; 
    EXEC SQL OPEN cur1;  

    EXEC SQL WHENEVER NOT FOUND DO BREAK; 
    while (1) 
    { 
        EXEC SQL FETCH FROM cur1 INTO :ii_a[0], :ii_a[1], :ii_a[2], :ii_a[3]; 
        ... 
    } 注意： EXEC SQL BEGIN DECLARE SECTION; 
    int ii_a[8]; 
EXEC SQL END DECLARE SECTION;  

    EXEC SQL DECLARE cur1 CURSOR FOR SELECT ii FROM t3; 
    EXEC SQL OPEN cur1;  

    EXEC SQL WHENEVER NOT FOUND DO BREAK;  

    while (1) 
    { 
        /* 错误 */ 
        EXEC SQL FETCH FROM cur1 INTO :ii_a; 
        ...
    } 无法将一个数组类型的查询结果直接映射到数组类型的宿主变量。 组合类型 ecpg不直接支持组合类型，例如：在struct中声明成员变量为date数据类型。但是可以单独访问每一个属性或者使用外部字符串表达。 对于如下示例，可以单独访问每一个属性： CREATE TYPE comp_t AS (intval integer, textval varchar(32)); 
CREATE TABLE t4 (compval comp_t); 
INSERT INTO t4 VALUES ( (256, 'PostgreSQL') ); 如下示例程序单独检索类型comp_t的每一个属性： EXEC SQL BEGIN DECLARE SECTION; 
    int intval; 
    varchar textval[33]; 
EXEC SQL END DECLARE SECTION;  

    /* 将组合类型列的每一个元素放在 SELECT 列表中。 */ 
    EXEC SQL DECLARE cur1 CURSOR FOR SELECT (compval).intval, (compval).textval FROM t4; 
    EXEC SQL OPEN cur1;  

    EXEC SQL WHENEVER NOT FOUND DO BREAK;  
    while (1) 
    { 
        /* 将组合类型列的每一个元素取到主变量中。 */ 
        EXEC SQL FETCH FROM cur1 INTO :intval, :textval; 
        printf("intval=%d, textval=%s\n", intval, textval.arr); 
    }  
    EXEC SQL CLOSE cur1; FETCH命令中从SQL语句接收并存储的结果宿主变量可以被集中在一个结构体中。结构体类型的宿主变量的详情可参考 处理字符串 章节。如下示例中两个宿主变量intval和textval变成comp_t结构体的成员，并且该结构体在FETCH命令中被指定： EXEC SQL BEGIN DECLARE SECTION; 
    typedef struct 
    { 
        int intval; 
        varchar textval[33]; 
    } comp_t; 
    comp_t compval; 
EXEC SQL END DECLARE SECTION;  

    /* 将组合类型列的每一个元素放在 SELECT 列表中。 */ 
    EXEC SQL DECLARE cur1 CURSOR FOR SELECT (compval).intval, (compval).textval FROM t4; 
    EXEC SQL OPEN cur1;  

    EXEC SQL WHENEVER NOT FOUND DO BREAK;  
    while (1) 
    { 
        /* 将 SELECT 列表中的所有值放入一个结构。 */ 
        EXEC SQL FETCH FROM cur1 INTO :compval; 
        printf("intval=%d, textval=%s\n", compval.intval, compval.textval.arr); 
    }  
    EXEC SQL CLOSE cur1; 虽然在FETCH命令中使用了结构体，但SELECT子句中的属性名依然要依次指定，为了更加方便，可以使用一个*来处理该组合类型值的所有属性，示例如下： ... 
EXEC SQL DECLARE cur1 CURSOR FOR SELECT (compval).* FROM t4; 
EXEC SQL OPEN cur1;  

EXEC SQL WHENEVER NOT FOUND DO BREAK;  

while (1) 
{ 
    /* 将 SELECT 列表中的所有值放入一个结构。 */ 
    EXEC SQL FETCH FROM cur1 INTO :compval; 
    printf("intval=%d, textval=%s\n", compval.intval, compval.textval.arr); 
} 
... 即便ecpg无法解析组合类型本身，也可以通过上述方法将组合类型映射到结构体中。 用户定义的基础类型 ecpg使用宿主变量来存放查询结果时，只支持ecpg提供的数据类型，不支持自定义的数据类型。对于通过CREATE TYPE创建的数据类型，无法通过宿主变量找到映射关系。 用户自定义类型可以使用外部字符串表达以及char[]或VARCHAR[]类型的宿主变量来处理。 数据类型complex的外部字符串表达是(%lf,%lf)，被定义在函数complex_in()内。如下示例把复杂类型值(1,1)和(3,3)插入到列a和b，并且查询它们的值。 EXEC SQL BEGIN DECLARE SECTION; 
    varchar a[64]; 
    varchar b[64];
EXEC SQL END DECLARE SECTION; 
    EXEC SQL INSERT INTO test_complex VALUES ('(1,1)', '(3,3)'); 
    EXEC SQL DECLARE cur1 CURSOR FOR SELECT a, b FROM test_complex; 
    EXEC SQL OPEN cur1; 

    EXEC SQL WHENEVER NOT FOUND DO BREAK; 

    while (1) 
    { 
       EXEC SQL FETCH FROM cur1 INTO :a, :b; 
       printf("a=%s, b=%s\n", a.arr, b.arr); 
    } 
    EXEC SQL CLOSE cur1; 示例输出： a=(1,1), b=(3,3)

